import { Component } from '@angular/core';
import { RouterOutlet, RouterLink } from '@angular/router';
import { Button } from 'primeng/button';

@Component({
  selector: 'app-root',
  imports: [RouterOutlet, RouterLink, Button],
  template: `
    <nav class="app-nav">
      <div class="nav-brand">Atomic POC</div>
      <div class="nav-links">
        <p-button label="Dashboard" [link]="true" routerLink="/dashboard" severity="secondary" [text]="true" />
        <p-button label="List" [link]="true" routerLink="/list" severity="secondary" [text]="true" />
        <p-button label="Detail" [link]="true" routerLink="/detail/1" severity="secondary" [text]="true" />
      </div>
    </nav>
    <main class="app-content">
      <router-outlet />
    </main>
  `,
  styles: `
    :host {
      display: flex;
      flex-direction: column;
      min-height: 100vh;
    }

    .app-nav {
      display: flex;
      align-items: center;
      gap: 24px;
      padding: 8px 24px;
      background: #FFFFFF;
      border-bottom: 1px solid #E7E5E4;
    }

    .nav-brand {
      font-family: Inter, sans-serif;
      font-size: 18px;
      font-weight: 700;
      color: #4338CA;
    }

    .nav-links {
      display: flex;
      gap: 8px;
    }

    .app-content {
      flex: 1;
      padding: 24px;
      background: #FAFAF9;
    }
  `,
})
export class App {}

